//10進数で表すとnをx進数で表す
fn base_number(x:usize, n:usize)->Vec<usize>{
    let mut x = x;
    let mut n = n;
    let mut r = 1;
    let mut q = x;
    let mut res = vec![];
    while(q>=n){
        r = q%n;
        res.push(r);
        q = q/n;
    }
    r = q%n;
    res.push(r);
    res.reverse();
    return res
}

//最大公約数
fn gcd(a:usize, b:usize)->usize{
    if b==0{return a;}
    return gcd(b, a%b);
}
//拡張GCD
//ax+by=1となる整数x,yを求める
fn extgcd(a:i64, b:i64, x:&mut i64, y:&mut i64) -> i64{
    let mut d = a;
    if b != 0{
        d = extgcd(b, a%b, y, x);
        *y -= (a/b)*(*x);
    }
    else{
        *x = 1;
        *y = 0;
    }
    return d;
}
//最小公倍数
fn lcm(a:usize, b:usize)->usize{
    return (b/gcd(a, b))*a;
}
//逆元
fn modinv(a:usize, M:usize)->usize{
    let mut b = M as i64;
    let mut u = 1 as i64;
    let mut v = 0 as i64;
    let mut a = a as i64;
    let mut m = M as i64;
    while(b>0){
        let mut t = a/b;
        a -= t*b;
        mem::swap(&mut a, &mut b);
        u-=t*v;
        mem::swap(&mut u, &mut v);
    }
    u%=m;
    if u<0{u+=m;}
    return u as usize;

}
