//座標圧縮２次元 [1, W]
fn linear_congruence(A:&Vec<i64>, B:&Vec<i64>, M:&Vec<i64>) -> (i64, i64){
    let mut x = 0;
    let mut m = 1;
    for i in 0..A.len(){
        let mut a = A[i]*m;
        let mut b = B[i]-A[i]*x;
        let mut d = gcd(M[i] as usize, a as usize) as i64;
        if (b%d != 0){ 
            return (0, -1);
        }
        let mut t= b/d*(modinv( (a/d) as  usize, (M[i]/d) as  usize) as i64)%(M[i]/d);
        x = x+m*t;
        m*=M[i]/d;
    }
    return (x%m, m);

}


//座標圧縮２次元 [1, W]
fn compress_2d(x1:&mut Vec<i64>, x2:&mut Vec<i64>, w:i64) -> Vec<i64>{
    let mut xs = vec![];
    for i in 0..x1.len(){
        for d in -1..2{
            let mut tx1 = x1[i]+d;
            let mut tx2 = x2[i]+d;
            if (1<=tx1 && tx1 <= w){
                xs.push(tx1);
            }
            if (1<=tx2 && tx2 <= w){
                xs.push(tx2);
            }
        }
    }
    let mut h = HashSet::new();
    for i in 0..xs.len(){
        h.insert(xs[i]);
    }
    let mut xs:Vec<i64> = h.into_iter().collect();
    xs.sort();
    return xs;
}


//セグメント木
struct segment_tree<I, Op>{
    n: usize,
    dat: Vec<I>,
    op:Op,
    e:I,
}
impl<I, Op> segment_tree<I, Op>
 
 
    where Op: Fn(I, I) -> I, I:Copy{
        
        pub fn new(n_:usize, op: Op, e:I)->Self{
            let mut n = 1;
            while(n<n_){n*=2;}
            segment_tree{n: n, dat:vec![e; 2*n-1], op:op, e:e}
        }
        pub fn update(&mut self, k:usize, a:I){
            let mut k = k;
            k += self.n-1;
            self.dat[k] = a;
            while(k>0){
                k = (k-1)/2;
                self.dat[k] = (self.op)(self.dat[k*2 + 1], self.dat[k*2+2]);
            }
        }

        pub fn query_sub(&self, a:usize, b:usize, k:usize, l:usize, r:usize) -> I{
            if r<=a || b<=l{return self.e;}
            if a<=l && r<=b{return self.dat[k];}
            else{
                let mut vl = self.query_sub(a, b, k*2+1, l, (l+r)/2);
                let mut vr = self.query_sub(a, b, k*2+2, (l+r)/2, r);
                return (self.op)(vl, vr);
            }
        }
        pub fn query(&self, a:usize, b:usize)->I{
            return self.query_sub(a, b, 0, 0, self.n);
        }
    }



//遅延評価セグメント木
// composition(a, b) -> b(a(x))
struct lazy_segment_tree<S, F, op, mapping, composition>{
    n: usize,
    op:op,
    mapping:mapping,
    composition:composition,
    s:S,
    f:F,
    dat: Vec<S>,
    lazy:Vec<F>,
    
}
impl<S, F, op, mapping, composition> lazy_segment_tree<S, F, op, mapping, composition>
 
 
    where op:Fn(S, S)->S, mapping:Fn(F, S)->S, composition:Fn(F, F)->F, S:Copy, F:Copy, S:PartialEq, F:PartialEq{
        
        pub fn new(n_:usize, s:S, f:F, op:op, mapping:mapping, composition:composition)->Self{
            let mut n = 1;
            while(n<n_){n*=2;}
            lazy_segment_tree{n:n, 
                              op:op, mapping:mapping, 
                              composition:composition, 
                              s:s, 
                              f:f, 
                              dat:vec![], 
                              lazy:vec![],
            }
        }
        pub fn build(&mut self, initial:&Vec<S>){
            for i in 0..self.n*2-1{
                self.dat.push(self.s.clone());
                self.lazy.push(self.f.clone());
            }
            for i in 0..initial.len(){
                self.dat[i+self.n-1] = initial[i];
            }
            for i in (0..self.n-1).rev(){
                self.dat[i] = (self.op)(self.dat[i*2+1], self.dat[i*2+2]);
            }
        }
        pub fn eval(&mut self, k:usize){
            if self.lazy[k] == self.f{
                return;
            }
            if k*2+1 < self.n*2-1{
                self.lazy[k*2+1] = (self.composition)(self.lazy[k*2+1], self.lazy[k]);
                self.lazy[k*2+2] = (self.composition)(self.lazy[k*2+2], self.lazy[k]);
            }
            self.dat[k] = (self.mapping)(self.lazy[k], self.dat[k]);
            self.lazy[k] = self.f;
        }
        pub fn update_sub(&mut self, a:usize, b:usize, x:F, k:usize, l:usize, r:usize)->S{
            self.eval(k);
            if r<=a || b<=l{
                return self.dat[k];
            }
            if a<=l && r<= b{
                self.lazy[k] = (self.composition)(self.lazy[k], x);
                return (self.mapping)(self.lazy[k], self.dat[k]);
            }
            let mut vr = self.update_sub(a, b, x, k*2+1, l, (l+r)/2);
            let mut vl = self.update_sub(a, b, x, k*2+2, (l+r)/2, r);
            self.dat[k] = (self.op)(vr, vl);
            return self.dat[k];
        }
        pub fn update(&mut self, a:usize, b:usize, x:F){
            self.update_sub(a, b, x, 0, 0, self.n);
        }
        pub fn query_sub(&mut self, a:usize, b:usize, k:usize, l:usize, r:usize)->S{
            self.eval(k);
            if r<= a || b <= l{
                return self.s;
            }
            else if a<= l && r<= b{
                return self.dat[k];
            }
            else{
                 let mut vl = self.query_sub(a, b, k*2+1, l, (l+r)/2);
                 let mut vr = self.query_sub(a, b, k*2+2, (l+r)/2, r);
                 return (self.op)(vl, vr);
            }
        }
        pub fn query(&mut self, a:usize, b:usize)->S{
            return self.query_sub(a, b, 0, 0, self.n);
        }

    }

//ダイクストラ法
fn dijkstra(s:usize, g:&Vec<Vec<(usize, i64)>>)->Vec<i64>{
    let mut dist = vec![INF;g.len()];
    dist[s] = 0;
    let mut h = BinaryHeap::new();
    h.push((0, s));
    while(h.len() != 0){
        let mut t = h.pop().unwrap();
        let mut d = t.0 * -1;
        let mut v = t.1;
        if dist[v]<d{
            continue;
        }
        for i in 0..g[v].len(){
            let n = g[v][i].0;
            let dd = g[v][i].1;
            if dist[n]>d+dd{
                dist[n] = d+dd;
                h.push((dist[n]*-1, n));
            }
        }
    }
    return dist;
}
fn dijkstra2(s:usize, g:&Vec<Vec<(i64, usize, usize)>>)->Vec<i64>{
    let mut dist = vec![INF;g.len()];
    dist[s] = 0;
    let mut h = BinaryHeap::new();
    h.push((0, s));
    while(h.len() != 0){
        let mut t = h.pop().unwrap();
        let mut d = t.0 * -1;
        let mut v = t.1;
        if dist[v]<d{
            continue;
        }
        for i in 0..g[v].len(){
            let n = g[v][i].1;
            let dd = g[v][i].0;
            if dist[n]>d+dd{
                dist[n] = d+dd;
                h.push((dist[n]*-1, n));
            }
        }
    }
    return dist;
}
fn dijkstra3(st:(usize, usize), go:(usize, usize), h:usize, w:usize, map:&Vec<Vec<char>>)->Vec<Vec<i64>>{ 
    let mut d = vec![vec![INF;w];h];
    d[st.0][st.1] = 0;
    let mut hh = BinaryHeap::new();
    hh.push((0, st));
    let mut dx = vec![0, 0, 1, -1];
    let mut dy = vec![1, -1, 0, 0];
    
    while(hh.len() != 0){
        let mut tt = hh.pop().unwrap();
        let mut dist = tt.0 as i64 * -1;
        let mut x = (tt.1).0;
        let mut y = (tt.1).1;
        if d[x][y]<dist{
            continue;
        }
        for i in 0..4{
            let mut nx = x as i64+dx[i];
            let mut ny = y as i64+dy[i];
            if 0<=nx && (nx<h as i64) && 0<= ny && ny<w as i64{
                let mut nx = nx as usize;
                let mut ny = ny as usize;
                if map[nx][ny] == '#'{
                    continue;
                }
                if d[nx][ny]>dist+1{
                    d[nx][ny]=dist+1;
                    hh.push((-1*(dist+1),(nx, ny)));
                }

            }
        }
    }
    return d;
}
