fn modpow(x:usize, n:usize) -> usize{
        let mut ans = 1;
        let mut n = n as usize;
        let mut x = x;
        while(n != 0){
            if (n&1 == 1){ans = ans*x%MODu;}
            x = x*x%MODu;
            n = n>>1;
        }
        ans
}
fn modpow2(x:i64, n:i64, m:i32) -> i64{
        let mut ans = 1;
        let mut n = n as i64;
        let mut x = x;
        while(n != 0){
            if (n&1 == 1){ans = ans*x%m as i64;}
            x = x*x%m as i64;
            n = n>>1;
        }
        ans
}



//ユニオンファインド木
struct union_find{
    par:Vec<usize>,
    rank:Vec<usize>,
    size:Vec<usize>,
    size_edge:Vec<usize>,
}
impl union_find{
    fn new(n:usize) -> union_find{
        let mut par = vec![0;n];
        for i in 0..n{
            par[i] = i;
        }
        union_find{
            par:par,
            rank:vec![0;n],
            size:vec![1;n],
            size_edge:vec![0;n],
        }
    }
    fn find(&mut self, x:usize) ->usize{
        if(self.par[x] == x){
            x
        }
        else{
            let p = self.par[x];
            let res = self.find(p);
            self.par[x] = res;
            res
        }
    }
    fn same(&mut self, a:usize, b:usize)->bool{
        self.find(a) == self.find(b)
    }
    fn unite(&mut self, a:usize, b:usize){
        let x = self.find(a);
        let y = self.find(b);
        if x != y{
            if (self.rank[x] < self.rank[y]){
                self.par[x] = y;
                self.size[y] += self.size[x];
                self.size_edge[y] += self.size_edge[x];
                self.size_edge[y] += 1;
            }
            else{
                self.par[y] = x;
                self.size[x] += self.size[y];
                self.size_edge[x] += self.size_edge[y];
                self.size_edge[x] += 1;
                if(self.rank[x] == self.rank[y]){ self.rank[x]+=1;}
            }

        }
        else{
            self.size_edge[x] += 1;
        }
    }
    fn check_size(&mut self, a:usize) -> usize{
        let x = self.find(a);
        let s = self.size[x];
        s
    }
}
//偏角ソート 反時計周り
fn norm(x:f64, y:f64)->f64{
    (x*x + y*y).sqrt()
}
fn rad(x:f64, y:f64)->f64{
    if y>=0.0{
        (x /norm(x, y)).acos()
    }
    else{
        2.0*PI - (x/norm(x,y)).acos()
    }
}
fn acos(v1:Vec<f64>, v2:Vec<f64>)->f64{
    ((v1[0]*v2[0] + v1[1]*v2[1])/(norm(v1[0], v1[1])*norm(v2[0], v2[1]))).acos()
}

fn argument_sort(xy:&mut Vec<Vec<f64>>){
    xy.sort_by(|a, b| rad(a[0], a[1]).partial_cmp(&(rad(b[0], b[1]))).unwrap());
}
fn argument_sort2(xy:&mut Vec<(f64, f64, usize)>){
    xy.sort_by(|a, b| rad(a.0, a.1).partial_cmp(&(rad(b.0, b.1))).unwrap());
}

//行列の掛け算 A*B
//
fn matmul(A:&Vec<Vec<i64>>, B:&Vec<Vec<i64>>) -> Vec<Vec<i64>>{
    let mut C = vec![vec![0;B[0].len()];A.len()];
    for i in 0..A.len(){
        for k in 0..B.len(){
            for j in 0..B[0].len(){
                C[i][j] += A[i][k]*B[k][j];
                C[i][j] %= MOD;
            }
        }
    }
    return C;
}
fn divisor(n:usize) -> Vec<usize>{
    let mut res:Vec<usize> = Vec::new();
    for i in 1..n+1{
        if i*i>n{break;}
        if n%i == 0{
            res.push(i);
            if i != n/i{
                res.push(n/i);
            }
        }
    }
    res
}


//xに10のpow乗を掛けて小数部分を消す
fn f64_trans(x:Vec<char>, pow:usize)->i64{
    let mut w = x.len();
    let mut a = vec![];
    let mut b = vec![];
    let mut f = false;
    let mut ism = false;
    if x[0] == '-'{
        ism = true;
    }
    for i in 0..x.len(){
        if x[i] == '-'{
            continue;
        }
        if x[i] == '.'{
            w = i;
            f = true;
        }
        else if f{
            b.push(x[i]);
        }
        else{
            a.push(x[i]);
        }
    }
        for i in 0..b.len(){
            a.push(b[i]);
        }
        for j in 0..pow-b.len(){
            a.push('0');
        }
    let mut now = 1;
    let mut res = 0;
    for i in (0..a.len()).rev(){
        res += now*(a[i] as i64 - '0' as i64);
        now*=10;
    }
    if ism{
        res*=-1;
    }
    return res;
}




//ローリングハッシュ
struct rolling_hash{
    base1:usize,
    base2:usize,
    mod1:usize,
    mod2:usize,
    hash1:Vec<usize>,
    hash2:Vec<usize>,
    power1:Vec<usize>,
    power2:Vec<usize>
}
impl rolling_hash{
    fn new(S:&Vec<usize>)->rolling_hash{
        let mut n = S.len();
        let mut base1 = 1007;
        let mut base2 = 2009;
        let mut mod1 = 1000000007;
        let mut mod2 = 1000000009;
        let mut hash1 = vec![0;n+1];
        let mut hash2 = vec![0;n+1];
        let mut power1 = vec![1;n+1];
        let mut power2 = vec![1;n+1];

        for i in 0..n{
            hash1[i+1] = (hash1[i] * base1 + S[i])%mod1;
            hash2[i+1] = (hash2[i] * base2 + S[i])%mod2;
            power1[i+1] = (power1[i] * base1)%mod1;
            power2[i+1] = (power2[i] * base2)%mod2;
        }

        return rolling_hash{
            hash1:hash1,
            hash2:hash2,
            power1:power1,
            power2:power2,
            base1:base1,
            base2:base2,
            mod1:mod1,
            mod2:mod2
        }
    }
    // [l, r) 
    fn get(&self, l:usize, r:usize)->(usize, usize){
        let mut res1 = self.hash1[r] as i64 - self.hash1[l] as i64 * self.power1[r-l] as i64%self.mod1 as i64;
        if (res1<0) {res1+= self.mod1 as i64;}
        let mut res2 = self.hash2[r] as i64 - self.hash2[l] as i64 * self.power2[r-l] as i64%self.mod2 as i64;
        if (res2<0) {res2+= self.mod2 as i64;}
        return (res1 as usize, res2 as usize);
    }
}

