#[allow(clippy::many_single_char_names)]
pub fn convolution_i64(a: &[i64], b: &[i64]) -> Vec<i64> {
    const M1: u64 = 754_974_721; // 2^24
    const M2: u64 = 167_772_161; // 2^25
    const M3: u64 = 469_762_049; // 2^26
    const M2M3: u64 = M2 * M3;
    const M1M3: u64 = M1 * M3;
    const M1M2: u64 = M1 * M2;
    const M1M2M3: u64 = M1M2.wrapping_mul(M3);

    modulus!(M1, M2, M3);

    if a.is_empty() || b.is_empty() {
        return vec![];
    }

    let (_, i1) = inv_gcd(M2M3 as _, M1 as _);
    let (_, i2) = inv_gcd(M1M3 as _, M2 as _);
    let (_, i3) = inv_gcd(M1M2 as _, M3 as _);

    let c1 = convolution_raw::<i64, M1>(a, b);
    let c2 = convolution_raw::<i64, M2>(a, b);
    let c3 = convolution_raw::<i64, M3>(a, b);

    c1.into_iter()
        .zip(c2)
        .zip(c3)
        .map(|((c1, c2), c3)| {
            const OFFSET: &[u64] = &[0, 0, M1M2M3, 2 * M1M2M3, 3 * M1M2M3];

            let mut x = [(c1, i1, M1, M2M3), (c2, i2, M2, M1M3), (c3, i3, M3, M1M2)]
                .iter()
                .map(|&(c, i, m1, m2)| c.wrapping_mul(i).rem_euclid(m1 as _).wrapping_mul(m2 as _))
                .fold(0, i64::wrapping_add);

            let mut diff = c1 - safe_mod(x, M1 as _);
            if diff < 0 {
                diff += M1 as i64;
            }
            x = x.wrapping_sub(OFFSET[diff.rem_euclid(5) as usize] as _);
            x
        })
        .collect()
}






//suffix array
struct suffix_array{
    n:usize,
    S:Vec<i64>,
    k:usize,
    sa:Vec<i64>,
    rank:Vec<i64>,
    tmp:Vec<i64>,
    lcp:Vec<i64>,
}


impl suffix_array{
    fn compare_sa(&mut self, i:&i64, j:&i64)-> std::cmp::Ordering{
        match self.rank[*i as usize].cmp(&(self.rank[*j as usize])){
            std::cmp::Ordering::Less => std::cmp::Ordering::Less,
            std::cmp::Ordering::Greater => std::cmp::Ordering::Greater,
            std::cmp::Ordering::Equal => {
                let mut ri =  {if (*i as usize+self.k)<=self.n{self.rank[*i as usize+self.k]}else{-1}};
                let mut rj =  {if (*j as usize+self.k)<=self.n{self.rank[*j as usize+self.k]}else{-1}};
                match ri.cmp(&rj){
                    std::cmp::Ordering::Less => std::cmp::Ordering::Less,
                    std::cmp::Ordering::Greater => std::cmp::Ordering::Greater,
                    std::cmp::Ordering::Equal => std::cmp::Ordering::Greater,
                }
                                            
            }
        }
    }


    fn new(S:&Vec<char>)->suffix_array{
        let mut n = S.len();
        let mut s = vec![];
        for i in 0..n{
            s.push(S[i] as i64);
        }
        let mut sa = vec![];
        let mut rank = vec![0;n+1];
        let mut tmp = vec![0;n+1];
        let mut lcp = vec![];
        return suffix_array{lcp:lcp, n:n, S:s, sa:sa, rank:rank, tmp:tmp, k:0};
    }
    fn build(&mut self){
        let mut sa = vec![0;self.n+1];
        for i in 0..self.n+1{
            sa[i] = i as i64;
            self.rank[i] = {if i<self.n{self.S[i]}else{-1}};
        }
        self.k = 1;
        while(true){
            if self.k>self.n{
                break;
            }
            sa.sort_by(|a, b| self.compare_sa(a, b));
            self.tmp[sa[0] as usize] = 0;
            for i in 1..self.n+1{
                let res = self.compare_sa(&(sa[i-1]), &(sa[i]));
                let mut zo = 0;
                if res == Ordering::Greater{
                    zo = 0;
                }
                else{
                    zo = 1;
                }
                self.tmp[sa[i]  as usize] = self.tmp[sa[i-1] as usize] + zo;
            }
            mem::swap(&mut self.rank, &mut self.tmp);
            self.k*=2;
        }
        self.sa = sa;
    }
    fn contain(&self, T:&Vec<i64>)->bool{
        let mut a = 0;
        let mut b = self.S.len();
        let mut t = T.as_slice();
        while(b-a>1){
            let mut c=  (a+b)/2;
            if &(self.S[ (self.sa[c] as usize)..(self.sa[c] as usize + T.len()) ]) < t{
                a = c;
            }
            else{
                b = c;
            }
        }
        return &(self.S[self.sa[b] as usize ..self.sa[b] as usize+T.len()]) == T.as_slice();
    }


    fn construct_lcp(&mut self){
        let mut n = self.S.len();
        for i in 0..n+1{
            self.rank[self.sa[i] as usize] = i as i64;
        }
        let mut h = 0;
        self.lcp = vec![0;n+1];
        self.lcp[0] = 0;
        for i in 0..n{
            let mut j = self.sa[self.rank[i] as usize -1];
            if h>0{
                h-=1;
            }
            while(true){
                if( (j as i64+h as i64) <n as i64) && ( (i as i64+h as i64)<n as i64){
                }
                else{
                    break;
                }
                if self.S[j as usize+h] != self.S[i as usize+h]{
                    break;
                }


                h+=1;
            }
            self.lcp[self.rank[i] as usize-1] = h as i64;
        }
    }
    fn compare_pat(&self, x:usize, pat:&Vec<i64>, size:usize)->i64{
        for i in 0..size{
            let a = pat[i];
            if x+i>=self.S.len(){
                return -1;
            }
            let b = self.S[x+i];
            if a<b{
                return -1;
            }
            else if a>b{
                return 1;
            }
        }
        return 0;
    }

    fn search_pattern_sub(&self, pat:&Vec<i64>, pat_size:usize)->i64{
        let mut low= 0;
        let mut high = self.S.len()-1;
        while low<=high{
            let mut mid =(low+high)/2;
            let mut r = self.compare_pat(self.sa[mid] as usize, pat, pat_size);
            if r==0{
                return mid as i64;
            }
            else if r>0{
                low = mid+1;
            }
            else{
                high = mid-1;
            }
        }
        return -1;
    }
    fn search_pat(&self, pat:&Vec<i64>)->i64{
        let mut pat_size = pat.len();
        let mut x = self.search_pattern_sub(pat, pat_size);
        if x >= 0{
            return self.sa[x as usize];
        }
        return -1;
    }
    fn search_pattern_all(&self, pat:&Vec<i64>)->Vec<i64>{
        let mut pat_size = pat.len();
        let mut x = self.search_pattern_sub(pat, pat_size);
        if x<0{
            return vec![];
        }
        let mut s = x-1;
        while s>=0 && self.compare_pat(self.sa[s as usize] as usize, pat, pat_size) == 0 {
            s -=1;
        }
        let mut e = x+1;
        while (e as usize) < self.S.len() && self.compare_pat(self.sa[e as usize] as usize, pat, pat_size) ==0{
            e+=1;
        }
        return self.sa[s as usize+1..e as usize].to_vec();
    }





}







//素因数分解
fn prime_factor(n:usize)->HashMap<usize, usize>{
    let mut res = HashMap::new();
    let mut n = n;
    for i in 2..n{
        if i*i>n{break;}
        while(n%i==0){
            *res.entry(i).or_insert(0)+=1;
            n/=i;
        }
    }
    if n != 1{
        res.insert(n, 1);
    }
    res
}

//素因数分解　クエリ
//let mut spf = smallest_prime_factor(10000);
//let mut f = factorization(x, &sfp);
fn smallest_prime_factor(n:usize)->Vec<usize>{
    let mut spf = vec![0;n+1];
    for i in 0..n+1{
        spf[i] = i;
    }
    for i in 2..INFu{
        if i*i>n{
            break;
        }
        if spf[i] == i{
            let mut j = i*i;
            while(j<=n){
                if spf[j] == j{
                    spf[j] = i;
                }
                j+=i;
            }
        }
    }

    return spf;
}
fn factorization(x:usize, spf:&Vec<usize>)->Vec<usize>{
    let mut res = vec![];
    let mut x = x;
    while(x != 1){
        res.push(spf[x]);
        x/=spf[x];
    }
    res.sort();
    return res;
}





























